import{_ as n,c as a,a1 as i,o as c}from"./chunks/framework.BDxlaA_J.js";const l=JSON.parse('{"title":"Xác định Hệ điều hành của Hệ thống Mục tiêu bằng TTL (Time-to-Live) và Kích thước Cửa sổ TCP sử dụng Wireshark","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/2-TTL.md","filePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/2-TTL.md"}'),h={name:"vi/categories/ethical-hacking-labs/2-scanning-networks/2-TTL.md"};function e(r,t,s,d,u,o){return c(),a("div",null,t[0]||(t[0]=[i('<h1 id="xac-đinh-he-đieu-hanh-cua-he-thong-muc-tieu-bang-ttl-time-to-live-va-kich-thuoc-cua-so-tcp-su-dung-wireshark" tabindex="-1">Xác định Hệ điều hành của Hệ thống Mục tiêu bằng TTL (Time-to-Live) và Kích thước Cửa sổ TCP sử dụng Wireshark <a class="header-anchor" href="#xac-đinh-he-đieu-hanh-cua-he-thong-muc-tieu-bang-ttl-time-to-live-va-kich-thuoc-cua-so-tcp-su-dung-wireshark" aria-label="Permalink to &quot;Xác định Hệ điều hành của Hệ thống Mục tiêu bằng TTL (Time-to-Live) và Kích thước Cửa sổ TCP sử dụng Wireshark&quot;">​</a></h1><p>Xác định hệ điều hành được sử dụng trên máy chủ mục tiêu cho phép kẻ tấn công tìm ra các lỗ hổng mà hệ thống có và các khai thác có thể hoạt động trên hệ thống để thực hiện các cuộc tấn công bổ sung.</p><p>Bắt phản hồi được tạo ra từ máy mục tiêu bằng các công cụ bắt gói tin như Wireshark và quan sát TTL và kích thước cửa sổ TCP.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Xác định hệ điều hành bằng TTL và kích thước cửa sổ TCP sử dụng Wireshark.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Máy Linux Ubuntu.</li><li>Máy Windows 7.</li><li>Máy Windows 10 (máy mục tiêu chạy Wireshark).</li></ul><h2 id="tong-quan-ve-bat-banner" tabindex="-1">Tổng quan về Bắt Banner: <a class="header-anchor" href="#tong-quan-ve-bat-banner" aria-label="Permalink to &quot;Tổng quan về Bắt Banner:&quot;">​</a></h2><p><strong>Có hai loại kỹ thuật bắt banner: chủ động và thụ động.</strong></p><p>Bắt banner (Banner grabbing) hoặc nhận dạng hệ điều hành (OS fingerprinting) là phương pháp xác định hệ điều hành đang chạy trên hệ thống mục tiêu từ xa.</p><table tabindex="0"><thead><tr><th>Hệ điều hành</th><th>Time-to-Live (TTL)</th><th>Kích thước cửa sổ TCP</th></tr></thead><tbody><tr><td>Linux (Kernel 2.4 và 2.6)</td><td>64</td><td>5840</td></tr><tr><td>FreeBSD</td><td>64</td><td>65535</td></tr><tr><td>OpenBSD</td><td>64</td><td>65535</td></tr><tr><td>Google customized Linux</td><td>64</td><td>5720</td></tr><tr><td>Windows XP</td><td>128</td><td>65535</td></tr><tr><td>Windows 7, Vista và Server 2008</td><td>128</td><td>8192</td></tr><tr><td>Cisco Router IOS 12.4</td><td>255</td><td>4128</td></tr></tbody></table><h2 id="su-dung-wireshark-đe-phat-hien-ttl" tabindex="-1">Sử dụng Wireshark để phát hiện TTL <a class="header-anchor" href="#su-dung-wireshark-đe-phat-hien-ttl" aria-label="Permalink to &quot;Sử dụng Wireshark để phát hiện TTL&quot;">​</a></h2><ol><li>Mở Wireshark trên máy Windows 10, chọn đúng giao diện mạng và bắt đầu bắt gói tin. (Giao diện có thể khác với môi trường lab của bạn).</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c68b799fcf3e60f75c0111fbcee309cd630def61/start-wireshark-1.png" alt="Wireshark Start" title="Wireshark Start!"></p><ol start="2"><li>Chuyển sang máy Ubuntu và bắt đầu ping máy Windows 10.</li></ol><p><code>ping -c 10 &lt;địa chỉ IP mục tiêu [Windows 10]&gt;</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c68b799fcf3e60f75c0111fbcee309cd630def61/ping-ubuntu-2.png" alt="Ubuntu Ping" title="Ubuntu Ping"></p><ol start="3"><li>Quay lại Wireshark và kiểm tra giao thức ICMP bằng cách chọn khung gói tin đã bắt; Mở rộng nút Internet Protocol Version trong chi tiết gói tin, bạn sẽ thấy TTL.</li></ol><p>Giá trị TTL được ghi nhận là <code>64</code> có nghĩa là yêu cầu ICMP đến từ máy dựa trên Linux.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b191cdf69129f7cfa87ddbaae31340b37c2b1bbc/wireshark-capturing-ubuntu64-3.png" alt="Wireshark Ubuntu Ping" title="Capturing Ubuntu ICMP"></p><ol start="4"><li>Làm mới Wireshark bằng cách bắt đầu một lần bắt mới và chuyển sang máy Windows 7.</li></ol><p>Bạn sẽ lặp lại quy trình tương tự, nhưng với máy Windows 7. Mở Command Prompt hoặc Powershell và ping máy Windows 10 đang chạy Wireshark.</p><p><code>ping &lt;địa chỉ IP mục tiêu&gt;</code></p><ol start="5"><li>Quay lại Wireshark trên máy Windows 10 và kiểm tra lại thông tin TTL tương tự.</li></ol><p>Giá trị TTL được ghi nhận là <code>128</code> có nghĩa là yêu cầu ICMP đến từ máy dựa trên Windows.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b191cdf69129f7cfa87ddbaae31340b37c2b1bbc/wireshark-capturing-win7-128-4.png" alt="Wireshark windows ping"></p>',26)]))}const b=n(h,[["render",e]]);export{l as __pageData,b as default};
